"""Table-driven fine configuration for flexible fine calculation."""from .constants import FINE_TIERS, MAXIMUM_FINE_AMOUNTclass FineConfiguration:    """    Configuration for fine calculation using a table-driven approach.    This encapsulates fine rules so they can change without affecting the calculator.    """    def __init__(self, rate_tiers=None, max_fine=MAXIMUM_FINE_AMOUNT):        self.rate_tiers = rate_tiers if rate_tiers is not None else FINE_TIERS.copy()        self.max_fine = max_fine    def calculate_fine(self, days_overdue):        """        Calculate fine based on configured rate tiers (cumulative).        Args:            days_overdue (int): Number of days overdue        Returns:            float: Calculated fine (capped at max_fine), 0.0 if days exceed all defined finite tiers.        """        if days_overdue <= 0:            return 0.0        total_fine = 0.0        remaining_days = days_overdue        for min_days, max_days, rate in self.rate_tiers:            if remaining_days <= 0:                break            # Determine how many days fall in this tier            # For infinite max, tier_days is simply remaining_days            if max_days == float('inf'):                tier_days = remaining_days            else:                tier_days = min(remaining_days, max_days - min_days + 1)            if tier_days > 0:                total_fine += tier_days * rate                remaining_days -= tier_days        # If days still remain and the last tier is NOT infinite, no policy applies        if remaining_days > 0:            return 0.0        return min(total_fine, self.max_fine)